// Pull call data and rules
const call = $('Loop Over Calls').item.json;
const utterances = call.utterances || [];
const rules = $('Fetch Rules').all().map(r => r.json);

const flags = [];

for (const rule of rules) {
  if (!rule.active) continue;

  // For compliance_required: flag if NO utterance from the required speaker contains ANY keyword
  if (rule.rule_type === 'compliance_required') {
    const speakerUtterances = rule.speaker
      ? utterances.filter(u => u.speaker === rule.speaker)
      : utterances;
    const found = speakerUtterances.some(u =>
      rule.keywords.some(kw => (u.text || '').toLowerCase().includes(kw.toLowerCase()))
    );
    if (!found) {
      flags.push({
        flag_name: rule.flag_name,
        rule_type: rule.rule_type,
        severity: rule.severity,
        matched_keyword: null,
        speaker: rule.speaker,
        utterance_index: null
      });
    }
    continue;
  }

  // For all other rule types: flag each utterance where a keyword IS found
  for (let i = 0; i < utterances.length; i++) {
    const u = utterances[i];
    if (rule.speaker && u.speaker !== rule.speaker) continue;
    const text = (u.text || '').toLowerCase();
    for (const kw of rule.keywords) {
      if (text.includes(kw.toLowerCase())) {
        flags.push({
          flag_name: rule.flag_name,
          rule_type: rule.rule_type,
          severity: rule.severity,
          matched_keyword: kw,
          speaker: u.speaker,
          utterance_index: i
        });
        break; // one flag per rule per utterance max
      }
    }
  }
}

// Build summary
const hasComplianceIssue = flags.some(f => f.rule_type.startsWith('compliance'));
const outcomeFlags = flags.filter(f => f.rule_type === 'outcome').map(f => f.flag_name);
const outcome = outcomeFlags.length ? outcomeFlags[0] : 'no_signal';

return [{
  json: {
    call_key: call.call_key,
    analysis_flags: flags,
    analysis_summary: {
      compliance_pass: !hasComplianceIssue,
      agent_sentiment_ok: !flags.some(f => f.rule_type === 'sentiment_agent'),
      outcome,
      flag_count: flags.length
    },
    analyzed_at: new Date().toISOString()
  }
}];
